//! Pneuma-specific math kernels: Conv1d, ConvTranspose1d, and cross-attention.
//!
//! These mirror the style of `math.rs`: a NEON SIMD path on aarch64 and a
//! scalar fallback elsewhere. They support the Whisper encoder's two stacked
//! Conv1d layers (mel input), the TTS vocoder's transposed conv upsampling,
//! and the decoder's cross-attention against cached encoder K/V.

#[cfg(target_arch = "aarch64")]
use std::arch::aarch64::*;

use crate::math::softmax;

// ── Conv1d ───────────────────────────────────────────────────────────

/// Output length for a 1D convolution / pooling op.
#[inline]
pub fn conv1d_out_len(in_len: usize, k: usize, stride: usize, pad: usize) -> usize {
    conv1d_out_len_dilated(in_len, k, stride, pad, 1)
}

/// 1D convolution over a row-major tensor.
pub fn conv1d(
    out: &mut [f32],
    x: &[f32],
    w: &[f32],
    bias: Option<&[f32]>,
    in_ch: usize,
    out_ch: usize,
    in_len: usize,
    k: usize,
    stride: usize,
    pad: usize,
) {
    conv1d_dilated(out, x, w, bias, in_ch, out_ch, in_len, k, stride, pad, 1);
}

/// 1D convolution over a row-major tensor with dilation.
pub fn conv1d_dilated(
    out: &mut [f32],
    x: &[f32],
    w: &[f32],
    bias: Option<&[f32]>,
    in_ch: usize,
    out_ch: usize,
    in_len: usize,
    k: usize,
    stride: usize,
    pad: usize,
    dilation: usize,
) {
    let out_len = conv1d_out_len_dilated(in_len, k, stride, pad, dilation);
    debug_assert_eq!(out.len(), out_ch * out_len);
    debug_assert_eq!(x.len(), in_ch * in_len);
    debug_assert_eq!(w.len(), out_ch * in_ch * k);

    for oc in 0..out_ch {
        let w_oc = oc * in_ch * k;
        let b = bias.map(|bb| bb[oc]).unwrap_or(0.0);
        for o in 0..out_len {
            let t_base = (o * stride) as isize - pad as isize;
            let mut acc = b;
            for kk in 0..k {
                let t = t_base + (kk * dilation) as isize;
                if t < 0 || (t as usize) >= in_len {
                    continue;
                }
                let t = t as usize;
                let w_row = &w[w_oc + kk..];
                acc += conv1d_reduce_in_ch(x, t, in_len, w_row, in_ch, k);
            }
            out[oc * out_len + o] = acc;
        }
    }
}

#[inline]
pub fn conv1d_out_len_dilated(
    in_len: usize,
    k: usize,
    stride: usize,
    pad: usize,
    dilation: usize,
) -> usize {
    let k_eff = (k - 1) * dilation + 1;
    (in_len + 2 * pad - k_eff) / stride + 1
}

/// Sum over `ic` of `x[ic, t] * w[oc, ic, kk]`, given the `kk` slice already
/// offset into the weight buffer (so the value at stride `k` is the next ic).
#[inline(always)]
fn conv1d_reduce_in_ch(
    x: &[f32],
    t: usize,
    in_len: usize,
    w_kk: &[f32],
    in_ch: usize,
    k: usize,
) -> f32 {
    // Channels are spaced by k in w_kk; spaced by in_len in x.
    // Build small contiguous gathers, then NEON-reduce.
    #[cfg(target_arch = "aarch64")]
    unsafe {
        let mut acc_v = vdupq_n_f32(0.0);
        let mut ic = 0usize;
        // 4-wide channel gather
        while ic + 4 <= in_ch {
            let xv = [
                *x.get_unchecked(ic * in_len + t),
                *x.get_unchecked((ic + 1) * in_len + t),
                *x.get_unchecked((ic + 2) * in_len + t),
                *x.get_unchecked((ic + 3) * in_len + t),
            ];
            let wv = [
                *w_kk.get_unchecked(ic * k),
                *w_kk.get_unchecked((ic + 1) * k),
                *w_kk.get_unchecked((ic + 2) * k),
                *w_kk.get_unchecked((ic + 3) * k),
            ];
            let xq = vld1q_f32(xv.as_ptr());
            let wq = vld1q_f32(wv.as_ptr());
            acc_v = vfmaq_f32(acc_v, xq, wq);
            ic += 4;
        }
        let mut acc = vaddvq_f32(acc_v);
        while ic < in_ch {
            acc += *x.get_unchecked(ic * in_len + t) * *w_kk.get_unchecked(ic * k);
            ic += 1;
        }
        acc
    }
    #[cfg(not(target_arch = "aarch64"))]
    {
        let mut acc = 0.0f32;
        for ic in 0..in_ch {
            acc += x[ic * in_len + t] * w_kk[ic * k];
        }
        acc
    }
}
/// Depthwise-separable 1D convolution over a row-major tensor.
/// Used by the Stochastic Duration Predictor (Track C).
#[inline]
pub fn conv1d_depthwise(
    out: &mut [f32],
    x: &[f32],
    w: &[f32],
    bias: Option<&[f32]>,
    channels: usize,
    in_len: usize,
    k: usize,
    stride: usize,
    pad: usize,
) {
    let out_len = conv1d_out_len(in_len, k, stride, pad);
    debug_assert_eq!(out.len(), channels * out_len);
    debug_assert_eq!(x.len(), channels * in_len);
    debug_assert_eq!(w.len(), channels * k);

    for c in 0..channels {
        let b = bias.map(|bb| bb[c]).unwrap_or(0.0);
        let w_c = &w[c * k..(c + 1) * k];
        for o in 0..out_len {
            let t_base = (o * stride) as isize - pad as isize;
            let mut acc = b;
            for kk in 0..k {
                let t = t_base + kk as isize;
                if t >= 0 && (t as usize) < in_len {
                    acc += x[c * in_len + t as usize] * w_c[kk];
                }
            }
            out[c * out_len + o] = acc;
        }
    }
}

pub fn conv1d_depthwise_separable(
    out: &mut [f32],
    x: &[f32],
    dw_w: &[f32], // (channels, 1, k)
    pw_w: &[f32], // (channels, channels, 1)
    dw_b: Option<&[f32]>,
    pw_b: Option<&[f32]>,
    channels: usize,
    in_len: usize,
    k: usize,
    stride: usize,
    pad: usize,
) {
    let out_len = conv1d_out_len(in_len, k, stride, pad);
    let mut dw_out = vec![0.0f32; channels * out_len];

    // 1. Depthwise pass
    for c in 0..channels {
        let b = dw_b.map(|bb| bb[c]).unwrap_or(0.0);
        let w_c = &dw_w[c * k..(c + 1) * k];
        let x_c = &x[c * in_len..(c + 1) * in_len];
        let out_c = &mut dw_out[c * out_len..(c + 1) * out_len];

        for o in 0..out_len {
            let t_base = (o * stride) as isize - pad as isize;
            let mut acc = b;
            for kk in 0..k {
                let t = t_base + kk as isize;
                if t >= 0 && (t as usize) < in_len {
                    acc += x_c[t as usize] * w_c[kk];
                }
            }
            out_c[o] = acc;
        }
    }

    // 2. Pointwise pass (1x1 conv)
    for oc in 0..channels {
        let b = pw_b.map(|bb| bb[oc]).unwrap_or(0.0);
        let w_oc = &pw_w[oc * channels..(oc + 1) * channels];
        for o in 0..out_len {
            let mut acc = b;
            for ic in 0..channels {
                acc += dw_out[ic * out_len + o] * w_oc[ic];
            }
            out[oc * out_len + o] = acc;
        }
    }
}

// ── ConvTranspose1d ──────────────────────────────────────────────────

/// 1D transposed convolution (vocoder upsampling, TTS Track B).
///
/// Layouts (all row-major, contiguous):
///   `x`:    `(in_ch, in_len)`
///   `w`:    `(in_ch, out_ch, k)`  — note: in_ch first, opposite of `conv1d`
///   `bias`: `(out_ch,)` optional, broadcast across the time axis
///   `out`:  `(out_ch, out_len)` where `out_len = (in_len - 1) * stride + k - 2*pad`
///
/// Implements the standard "scatter-add" formulation: for each input position
/// `i`, scatter `x[:, i] * w[:, :, kk]` into output position `i*stride + kk - pad`
/// for every kernel tap `kk`. Out-of-range output positions are skipped.
pub fn conv_transpose1d(
    out: &mut [f32],
    x: &[f32],
    w: &[f32],
    bias: Option<&[f32]>,
    in_ch: usize,
    out_ch: usize,
    in_len: usize,
    k: usize,
    stride: usize,
    pad: usize,
) {
    // out_len = (in_len - 1) * stride + k - 2*pad. Guard against underflow when
    // pad is large vs. effective kernel span (shouldn't happen in practice).
    let span = (in_len.saturating_sub(1)) * stride + k;
    let out_len = span.saturating_sub(2 * pad);
    debug_assert_eq!(out.len(), out_ch * out_len);
    debug_assert_eq!(x.len(), in_ch * in_len);
    debug_assert_eq!(w.len(), in_ch * out_ch * k);

    // Initialise output with bias (or zero).
    if let Some(bb) = bias {
        for oc in 0..out_ch {
            let row = &mut out[oc * out_len..(oc + 1) * out_len];
            let bv = bb[oc];
            for v in row.iter_mut() {
                *v = bv;
            }
        }
    } else {
        for v in out.iter_mut() {
            *v = 0.0;
        }
    }

    // Scatter-add. Outer loops keep memory access on `out` mostly sequential
    // per (oc, t_out).
    for ic in 0..in_ch {
        for oc in 0..out_ch {
            for i in 0..in_len {
                let x_val = x[ic * in_len + i];
                for kk in 0..k {
                    let t_out = i * stride + kk;
                    if t_out < pad || t_out - pad >= out_len {
                        continue;
                    }
                    let t_out = t_out - pad;
                    let w_val = w[((ic * out_ch + oc) * k) + kk];
                    out[oc * out_len + t_out] += x_val * w_val;
                }
            }
        }
    }
}

// ── Cross-attention ──────────────────────────────────────────────────

/// Cross-attention helper. Q comes from the decoder; K, V are cached from the
/// encoder output. No causal mask — every decoder position attends to every
/// encoder position.
///
/// Layouts (all row-major, contiguous):
///   `q`:   `(seq_q,  num_heads, head_dim)` — current decoder query
///   `k`:   `(seq_kv, num_heads, head_dim)` — encoder K (cached, no growth)
///   `v`:   `(seq_kv, num_heads, head_dim)` — encoder V (cached, no growth)
///   `out`: `(seq_q,  num_heads, head_dim)` — attention output
///
/// Score scale is `1/sqrt(head_dim)`. Softmax is computed per (query position,
/// head) over the `seq_kv` axis.
pub fn cross_attention(
    out: &mut [f32],
    q: &[f32],
    k: &[f32],
    v: &[f32],
    seq_q: usize,
    seq_kv: usize,
    num_heads: usize,
    head_dim: usize,
) {
    debug_assert_eq!(q.len(), seq_q * num_heads * head_dim);
    debug_assert_eq!(k.len(), seq_kv * num_heads * head_dim);
    debug_assert_eq!(v.len(), seq_kv * num_heads * head_dim);
    debug_assert_eq!(out.len(), seq_q * num_heads * head_dim);

    let scale = 1.0 / (head_dim as f32).sqrt();
    let row = num_heads * head_dim;
    let mut scores = vec![0.0f32; seq_kv];

    for qi in 0..seq_q {
        let q_row = qi * row;
        let o_row = qi * row;
        for h in 0..num_heads {
            let q_off = q_row + h * head_dim;
            // 1) scores[j] = (Q . K_j) * scale
            for j in 0..seq_kv {
                let k_off = j * row + h * head_dim;
                scores[j] =
                    cross_attn_dot(&q[q_off..q_off + head_dim], &k[k_off..k_off + head_dim])
                        * scale;
            }
            // 2) softmax(scores) in place
            softmax(&mut scores);
            // 3) out[qi, h, :] = sum_j scores[j] * V[j, h, :]
            let o_off = o_row + h * head_dim;
            for d in 0..head_dim {
                out[o_off + d] = 0.0;
            }
            for j in 0..seq_kv {
                let v_off = j * row + h * head_dim;
                let s = scores[j];
                cross_attn_axpy(
                    &mut out[o_off..o_off + head_dim],
                    &v[v_off..v_off + head_dim],
                    s,
                );
            }
        }
    }
}

#[inline(always)]
fn cross_attn_dot(a: &[f32], b: &[f32]) -> f32 {
    debug_assert_eq!(a.len(), b.len());
    #[cfg(target_arch = "aarch64")]
    unsafe {
        let n = a.len();
        let chunks = n / 4;
        let mut acc = vdupq_n_f32(0.0);
        let ap = a.as_ptr();
        let bp = b.as_ptr();
        for i in 0..chunks {
            acc = vfmaq_f32(acc, vld1q_f32(ap.add(i * 4)), vld1q_f32(bp.add(i * 4)));
        }
        let mut s = vaddvq_f32(acc);
        let base = chunks * 4;
        for i in base..n {
            s += *ap.add(i) * *bp.add(i);
        }
        s
    }
    #[cfg(not(target_arch = "aarch64"))]
    {
        let mut s = 0.0f32;
        for i in 0..a.len() {
            s += a[i] * b[i];
        }
        s
    }
}

/// `out += weight * src` (NEON-vectorised on aarch64).
#[inline(always)]
fn cross_attn_axpy(out: &mut [f32], src: &[f32], weight: f32) {
    debug_assert_eq!(out.len(), src.len());
    let n = out.len();
    #[cfg(target_arch = "aarch64")]
    unsafe {
        let w = vdupq_n_f32(weight);
        let mut i = 0usize;
        while i + 4 <= n {
            let o = vld1q_f32(out.as_ptr().add(i));
            let s = vld1q_f32(src.as_ptr().add(i));
            vst1q_f32(out.as_mut_ptr().add(i), vfmaq_f32(o, s, w));
            i += 4;
        }
        while i < n {
            *out.get_unchecked_mut(i) += weight * *src.get_unchecked(i);
            i += 1;
        }
    }
    #[cfg(not(target_arch = "aarch64"))]
    {
        for i in 0..n {
            out[i] += weight * src[i];
        }
    }
}
